            Summary = "Complete reference for every field, stage, entry rule, and action in the Customer Returns module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 3,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/customer-returns"]""",
            Tags = """["customer-returns","sales","reference"]""",
            ContentJson = """{"title":"Customer Returns Field Reference","groups":[{"heading":"What's on a Return","items":[{"label":"RMA number","value":"Each return gets its own number like RMA-00001, assigned automatically in order. You cannot set or change it yourself."},{"label":"Customer (required)","value":"The customer who sent the goods back. Every return is tied to one customer's account."},{"label":"Original job (required)","value":"The production job that made the returned goods, so the return traces straight back to where it came from."},{"label":"Rework job (optional)","value":"The rework job for this return, if one was made. Its title starts with '[Rework]'. You can create it while logging the return or link it later."},{"label":"Reason (required)","value":"Why the goods came back. Keep it specific and useful. Required, up to 1000 characters."},{"label":"Notes (optional)","value":"Extra context such as PO numbers, quantities, shipping details, or customer messages. Optional, up to 2000 characters."},{"label":"Stage","value":"Where the return is in its life: Received, In Inspection, Rework Ordered, Resolved, or Closed. See the Stages section for the rules."},{"label":"Return date (required)","value":"When the goods came back, or are expected back. Set when you log the return."},{"label":"Inspected by (optional)","value":"Who inspected the returned goods."},{"label":"Inspected on (optional)","value":"When the inspection happened."},{"label":"Inspection notes (optional)","value":"What the inspection found: measurements, defect descriptions, and root-cause notes. Up to 2000 characters."},{"label":"Created (automatic)","value":"When the return was first logged. Filled in for you."},{"label":"Last updated (automatic)","value":"When the return was last changed. Filled in for you."},{"label":"Created by (automatic)","value":"Who logged the return. Filled in for you."}]},{"heading":"Return Stages","items":[{"label":"Received","value":"The starting stage. The return is logged; the goods may or may not have arrived yet. It can move to any stage except straight to Closed."},{"label":"In Inspection","value":"The goods are being inspected and findings are being written down. A middle stage between Received and deciding how to resolve it."},{"label":"Rework Ordered","value":"A rework job has been created and linked. This happens automatically when you ask for a rework job while logging the return. The rework job shows up on the board."},{"label":"Resolved","value":"The fix is done. You cannot resolve a return that is already Closed, and a return must be resolved before it can be closed."},{"label":"Closed","value":"The final stage, and it cannot be undone. Only resolved returns can be closed. Once closed, nothing more can change."}]},{"heading":"What You Can Do","items":[{"label":"See all returns","value":"Open the list to see every return, newest first. Filter by customer or by stage to narrow it down."},{"label":"Open a return","value":"Click a return to see its full detail: the customer, the jobs, the reason, who inspected it and when, and all the notes."},{"label":"Log a new return","value":"Use New Return to record one. Give the customer, the original job, a reason, and a return date; notes are optional. Saving creates the RMA number."},{"label":"Update a return","value":"Edit the reason, the notes, or the inspection notes at any time. Only the fields you change are updated."},{"label":"Resolve a return","value":"Mark a return resolved once the fix is done. This is blocked if the return is already closed."},{"label":"Close a return","value":"Close a resolved return to finish it for good. This is blocked unless the return has been resolved first."}]},{"heading":"Rules to Know","items":[{"label":"Customer","value":"Required. You must pick a real customer."},{"label":"Original job","value":"Required. You must pick a real job."},{"label":"Reason","value":"Required. Cannot be blank. Up to 1000 characters."},{"label":"Notes","value":"Optional. Up to 2000 characters."},{"label":"Inspection notes","value":"Optional. Up to 2000 characters."},{"label":"Resolving","value":"You cannot resolve a return that is already closed."},{"label":"Closing","value":"You can only close a return that has been resolved first."}]},{"heading":"When a Rework Job Is Created","items":[{"label":"How it starts","value":"Turn on 'Create Rework Job' when you log the return, and the system builds the job for you."},{"label":"Job number","value":"A new job number is assigned automatically, next in line."},{"label":"Title","value":"The original job's title with a '[Rework]' prefix, for example '[Rework] Aluminum Housing Batch 5'."},{"label":"Description","value":"A short note that records the RMA number and the reason for the return, so anyone on the board knows why the job exists."},{"label":"Track","value":"The same track as the original job."},{"label":"Starting stage","value":"The first stage of that track."},{"label":"Priority","value":"Always High."},{"label":"Assigned to","value":"The same person as the original job, if it had one."},{"label":"Link","value":"The rework job is linked to the original job on the board."},{"label":"Return stage","value":"The return moves to Rework Ordered as soon as the rework job is created."}]},{"heading":"Who Can Use It","items":[{"label":"Who has access","value":"Admins, Managers, and Office Managers can work with customer returns."},{"label":"Where it lives","value":"Everything happens on the Customer Returns page."}]},{"heading":"What You See on a Return","items":[{"label":"In the list","value":"Each row shows the RMA number, the customer, the original job, the rework job (if any), the current stage, the reason, and the return date."},{"label":"On the detail panel","value":"The full record adds the original job's title, any notes, and the inspection details — who inspected it, when, and what they found — along with when the return was created and last updated."}]}]}"""
        });

        // ── Using the UI (Walkthrough) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
