            AppRoutes = """["/customer-returns"]""",
            Tags = """["customer-returns","sales","walkthrough"]""",
            ContentJson = """{"appRoute":"/customer-returns","startButtonLabel":"Tour Customer Returns","steps":[{"element":"app-page-header","popover":{"title":"Customer Returns","description":"This is the Customer Returns page. It lists every return customers have sent back — for defects, wrong specs, shipping damage, or other quality issues. Each return has its own RMA number and moves through stages from Received to Closed.","side":"bottom"}},{"element":"app-input","popover":{"title":"Search Returns","description":"Type here to narrow the list — by RMA number, customer name, or original job number. This is the quickest way to find one customer's return when the list is long.","side":"bottom"}},{"element":"app-select","popover":{"title":"Filter by Stage","description":"Pick a stage from this menu to show only returns at that point: Received, In Inspection, Rework Ordered, Resolved, or Closed. Leave it on 'All Statuses' to see everything. Filtering is the fastest way to find returns that still need attention.","side":"bottom"}},{"element":".action-btn:not(.action-btn--create)","popover":{"title":"Apply Filters","description":"Click Filter to apply your search text and stage choice. The list reloads to show only the returns that match.","side":"bottom"}},{"element":"[data-testid='new-return-btn']","popover":{"title":"New Return","description":"Click New Return to log a return. The form asks for the customer, the original job that made the goods, a reason, an optional return date, and optional notes. Saving creates the RMA number and sets the stage to Received.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"The Returns List","description":"Each row shows the RMA number, customer, original job, a colored stage label, the reason, the return date, and when it was logged. Click a column header to sort. The label color shows the stage at a glance: blue for Received, teal for In Inspection, amber for Rework Ordered, green for Resolved, and gray for Closed.","side":"top"}},{"element":"app-data-table","popover":{"title":"Open a Return","description":"Click any row to open that return's detail panel. It shows the full record — customer, jobs, reason, inspection findings, and an activity history — and is where you resolve the return and then close it. You can also bookmark or share the link to jump straight back to that return.","side":"top"}}]}"""
        });

        // ── Resolving and Closing (Article) ──────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Customer Returns — Resolving and Closing",
            Slug = "customer-returns-resolving-and-closing",
            Summary = "How to work a return from the detail panel: recording inspection findings, resolving with notes, closing with confirmation, and reading the activity timeline.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 6,
            AppRoutes = """["/customer-returns"]""",
            Tags = """["customer-returns","sales"]""",
            ContentJson = """{"body":"## Customer Returns — Resolving and Closing\n\nOnce a return exists, the rest of the work happens in its **detail panel**. From the Customer Returns list, click any row to open it. You can bookmark or share the link so a colleague opens the exact same return.\n\n### Reading the Detail Panel\n\nThe panel header shows the RMA number (for example, RMA-00007). Below it, everything about the return is laid out:\n\n- **Stage** — a colored label for where the return is now (Received, In Inspection, Rework Ordered, Resolved, or Closed).\n- **Customer** — the account that sent the goods back.\n- **Original Job** — the job that made the returned goods.\n- **Rework Job** — shown only when a rework job has been created for this return.\n- **Return Date** — when the goods came back, or are expected back.\n- **Reason** — why the goods came back (always shown).\n- **Notes** — extra context, shown only if you entered any.\n- **Inspection details** — who inspected the return, when, and what they found; these fill in after the return is inspected and resolved.\n\nThe buttons in the panel change with the return's stage, so you only ever see the action that makes sense next.\n\n### Resolving a Return\n\nWhen a return is in **Received**, **In Inspection**, or **Rework Ordered**, a **Resolve** button appears.\n\n1. Click **Resolve**. A small window opens with one field: **Inspection Notes (optional)**.\n2. Record what you found — measurements, the defect, the root cause, or the fix you made. These notes stay on the record for good and feed your quality trends. (The field is optional, so you can resolve without notes, but capturing findings is strongly recommended.)\n3. Click **Resolve** to confirm. The stage changes to **Resolved**, your notes are saved, and the panel refreshes. A short confirmation message appears.\n\nResolving means the issue has been handled — through rework, a replacement, a credit, or a decision that no action is needed. You can resolve straight from any active stage; the return does not have to pass through In Inspection or Rework Ordered first.\n\n### Closing a Return\n\nOnce a return is **Resolved**, the Resolve button is replaced by a **Close** button.\n\n1. Click **Close**. A prompt asks you to confirm closing this return — closing is final.\n2. Confirm. The stage changes to **Closed** and a short confirmation message appears.\n\n**Closing cannot be undone.** A closed return cannot be reopened, resolved again, or edited. Only resolved returns can be closed — resolving first, then closing, is what keeps the audit trail clean: every closed return went through a real resolution first. Because closing is final, you have to confirm before it happens.\n\n### The Activity History\n\nAt the bottom of the panel is the **activity history** — a time-ordered record for that return that cannot be edited. Every meaningful event is captured: when the return was logged, updated, resolved, and closed, along with who did it and when.\n\nUse it to answer 'what happened to this return, and who handled it?' without leaving the panel. Because the entries cannot be changed, it is a trustworthy record — useful during customer disputes, quality reviews, or when piecing together how a recurring issue was handled across several returns.\n\n### Tips\n\n- **Always resolve before you close.** The Close button only shows up on resolved returns; there is no shortcut straight to Closed.\n- **Capture inspection notes when you resolve.** It is the natural moment, and the notes are then visible to anyone who opens the return later.\n- **Share the link** to point a colleague at a specific return instead of describing how to find it.\n- **Check the history before closing** to confirm the fix was really done.","sections":[]}"""
